mapper.sql:
select ODPS_PROJECT_NAME as projectName,BUSINESS_NAME as businessName,NODE_NAME as nodeName,
PRG_TYPE as prgType,BEGIN_WAITTIME_TIME as startTime,FINISH_TIME as finishTime,
OUT_TABLE_NUM as outTableNum,LAST_OUT_RECORDS as outRecordsNum,STATUS as status,
CASE WHEN CPU_CONSUMPTION = '0' THEN '0'
WHEN to_char(CPU_CONSUMPTION,'fm999999999990.00') = '0.00' THEN '0'
ELSE to_char(CPU_CONSUMPTION,'fm999999999990.00') END AS cpuConsumption,
CASE WHEN MEMORY_CONSUMPTION = '0' THEN '0'
WHEN to_char(MEMORY_CONSUMPTION,'fm999999999990.00') = '0.00' THEN '0'
ELSE to_char(MEMORY_CONSUMPTION,'fm999999999990.00') END AS memoryConsumption,
round((FINISH_TIME-BEGIN_WAITTIME_TIME)*24*60*60) as runningTime,TASK_ID as taskId
from M_FLOW_THREE

	PRG_TYPE != 98

		and NODE_NAME like '%${queryParams.input}%'


		and TASK_ID in (${queryParams.taskIds})


		and BEGIN_WAITTIME_TIME >= to_date(#{queryParams.taskOpenDateBegin,jdbcType=VARCHAR},'yyyy-mm-dd HH24:mi:ss')


		and BEGIN_WAITTIME_TIME  <   to_date(#{queryParams.taskOpenDateEnd,jdbcType=VARCHAR},'yyyy-mm-dd HH24:mi:ss')


		and FINISH_TIME >= to_date(#{queryParams.taskEndDateBegin,jdbcType=VARCHAR},'yyyy-mm-dd HH24:mi:ss')


		and FINISH_TIME  <   to_date(#{queryParams.taskEndDateEnd,jdbcType=VARCHAR},'yyyy-mm-dd HH24:mi:ss')


		and round((FINISH_TIME-BEGIN_WAITTIME_TIME)*24*60*60) >= #{queryParams.runningTimeBegin,jdbcType=VARCHAR}


		and round((FINISH_TIME-BEGIN_WAITTIME_TIME)*24*60*60)  <=   #{queryParams.runningTimeEnd,jdbcType=VARCHAR}



		and to_number(LAST_OUT_RECORDS) >= #{queryParams.outputRecordBegin,jdbcType=VARCHAR}


		and to_number(LAST_OUT_RECORDS)  <=  #{queryParams.outputRecordEnd,jdbcType=VARCHAR}



		and to_number(MEMORY_CONSUMPTION) >= #{queryParams.memoryConsumptionBegin,jdbcType=VARCHAR}


		and to_number(MEMORY_CONSUMPTION)  <=   #{queryParams.memoryConsumptionEnd,jdbcType=VARCHAR}


		and to_number(CPU_CONSUMPTION) >= #{queryParams.cpuConsumptionBegin,jdbcType=VARCHAR}


		and to_number(CPU_CONSUMPTION)  <=   #{queryParams.cpuConsumptionEnd,jdbcType=VARCHAR}

